module top_module (
	input clk,
	input in_signal,
	output reg edge_detected);reg prev_signal;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		prev_signal <= in_signal;
		edge_detected <= (in_signal & ~prev_signal);
	end

endmodule
